import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.isActive
import kotlinx.coroutines.launch

class MusicService : Service(), AudioManager.OnAudioFocusChangeListener {

    companion object {
        const val NOTIFICATION_ID = 1001

        const val ACTION_PLAY_PAUSE = "com.example.music.action.PLAY_PAUSE"
        const val ACTION_NEXT = "com.example.music.action.NEXT"
        const val ACTION_PREVIOUS = "com.example.music.action.PREVIOUS"
        const val ACTION_STOP = "com.example.music.action.STOP"
        const val ACTION_REPEAT_TOGGLE = "com.example.music.action.REPEAT_TOGGLE"
        const val ACTION_SHUFFLE_TOGGLE = "com.example.music.action.SHUFFLE_TOGGLE"
    }

    inner class MusicBinder : Binder() {
        fun getService(): MusicService = this@MusicService
    }

    private val binder = MusicBinder()
    private val scope = CoroutineScope(Dispatchers.Main + Job())

    private lateinit var audioManager: AudioManager
    private lateinit var notificationHelper: PlaybackNotificationHelper

    private var mediaPlayer: MediaPlayer? = null
    private var audioFocusRequest: AudioFocusRequest? = null
    private var progressJob: Job? = null

    private var currentIndex = -1
    private var shuffledIndices: List<Int> = emptyList()
    private var currentAlbumArt: Bitmap? = null

    private val _playbackState = MutableStateFlow<PlayerState>(PlayerState.Idle)
    val playbackState: StateFlow<PlayerState> = _playbackState.asStateFlow()

    private val _queue = MutableStateFlow<List<Song>>(emptyList())
    val queue: StateFlow<List<Song>> = _queue.asStateFlow()

    private val _repeatMode = MutableStateFlow(RepeatMode.ALL)
    val repeatModeFlow: StateFlow<RepeatMode> = _repeatMode.asStateFlow()

    private val _shuffleEnabled = MutableStateFlow(false)
    val shuffleEnabledFlow: StateFlow<Boolean> = _shuffleEnabled.asStateFlow()

    override fun onCreate() {
        super.onCreate()
        audioManager = getSystemService(AudioManager::class.java)
        notificationHelper = PlaybackNotificationHelper(this)
    }

    override fun onBind(intent: Intent?): IBinder = binder

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        val action = intent?.action
        when (action) {
            ACTION_PLAY_PAUSE,
            PlaybackNotificationHelper.ACTION_PLAY,
            PlaybackNotificationHelper.ACTION_PAUSE -> {
                when (_playbackState.value) {
                    is PlayerState.Playing -> {
                        if (action == PlaybackNotificationHelper.ACTION_PLAY) Unit else pause()
                    }

                    is PlayerState.Paused -> {
                        if (action == PlaybackNotificationHelper.ACTION_PAUSE) Unit else resume()
                    }

                    else -> Unit
                }
            }

            ACTION_NEXT,
            PlaybackNotificationHelper.ACTION_NEXT -> skipNext()

            ACTION_PREVIOUS,
            PlaybackNotificationHelper.ACTION_PREVIOUS -> skipPrevious()

            ACTION_STOP,
            PlaybackNotificationHelper.ACTION_STOP -> stopPlayback()

            ACTION_REPEAT_TOGGLE,
            PlaybackNotificationHelper.ACTION_REPEAT -> setRepeatMode(nextRepeatMode(_repeatMode.value))

            ACTION_SHUFFLE_TOGGLE,
            PlaybackNotificationHelper.ACTION_SHUFFLE -> setShuffle(!_shuffleEnabled.value)
        }

        return START_STICKY
    }

    fun playSong(song: Song, queue: List<Song>) {
        val resolvedQueue = queue.ifEmpty { listOf(song) }
        val indexInQueue = resolvedQueue.indexOfFirst { it.id == song.id }
        if (indexInQueue < 0) return

        _queue.value = resolvedQueue
        currentIndex = indexInQueue

        if (!requestAudioFocus()) {
            _playbackState.value = PlayerState.Error("Failed to get audio focus", song)
            refreshNotificationForCurrentState()
            return
        }

        _playbackState.value = PlayerState.Preparing
        releasePlayer()

        mediaPlayer = MediaPlayer().apply {
            setAudioAttributes(
                AudioAttributes.Builder()
                    .setUsage(AudioAttributes.USAGE_MEDIA)
                    .setContentType(AudioAttributes.CONTENT_TYPE_MUSIC)
                    .build()
            )

            setOnPreparedListener { player ->
                player.start()
                _playbackState.value = PlayerState.Playing(song, 0L, song.durationMs)
                startProgressUpdates()
                startPlaybackForeground(song)
            }

            setOnCompletionListener {
                onSongCompleted()
            }

            setOnErrorListener { _, what, _ ->
                _playbackState.value = PlayerState.Error("Playback error: $what", song)
                refreshNotificationForCurrentState()
                true
            }

            setDataSource(this@MusicService, song.contentUri)
            prepareAsync()
        }
    }

    fun pause() {
        mediaPlayer?.pause()
        val state = _playbackState.value
        if (state is PlayerState.Playing) {
            _playbackState.value = PlayerState.Paused(state.song, state.position, state.duration)
            stopProgressUpdates()
            stopForeground(STOP_FOREGROUND_DETACH)
            refreshNotificationForCurrentState()
        }
    }

    fun resume() {
        mediaPlayer?.start()
        val state = _playbackState.value
        if (state is PlayerState.Paused) {
            _playbackState.value = PlayerState.Playing(state.song, state.position, state.duration)
            startProgressUpdates()
            startPlaybackForeground(state.song)
        }
    }

    fun seekTo(positionMs: Long) {
        mediaPlayer?.seekTo(positionMs.coerceAtLeast(0L).toInt())
        updatePlaybackPosition()
    }

    fun skipNext() {
        val songs = _queue.value
        if (songs.isEmpty() || currentIndex !in songs.indices) return

        val nextIndex = if (_shuffleEnabled.value) {
            nextShuffledIndex()
        } else {
            (currentIndex + 1) % songs.size
        }

        playSong(songs[nextIndex], songs)
    }

    fun skipPrevious() {
        val songs = _queue.value
        if (songs.isEmpty() || currentIndex !in songs.indices) return

        val state = _playbackState.value
        if (state is PlayerState.Playing && state.position > PlayerConstants.SEEK_BACK_THRESHOLD_MS) {
            seekTo(0)
            return
        }

        val prevIndex = if (currentIndex == 0) songs.lastIndex else currentIndex - 1
        playSong(songs[prevIndex], songs)
    }

    fun setRepeatMode(mode: RepeatMode) {
        _repeatMode.value = mode
        refreshNotificationForCurrentState()
    }

    fun setShuffle(enabled: Boolean) {
        _shuffleEnabled.value = enabled
        shuffledIndices = if (enabled) _queue.value.indices.shuffled() else emptyList()
        refreshNotificationForCurrentState()
    }

    fun updateQueue(queue: List<Song>) {
        _queue.value = queue
        if (currentIndex !in queue.indices) {
            currentIndex = queue.indexOfFirst { it.id == currentSong(_playbackState.value)?.id }
        }
        if (_shuffleEnabled.value) {
            shuffledIndices = queue.indices.shuffled()
        }
    }

    private fun onSongCompleted() {
        when (_repeatMode.value) {
            RepeatMode.ONE -> {
                val song = _queue.value.getOrNull(currentIndex)
                if (song != null) {
                    playSong(song, _queue.value)
                }
            }

            RepeatMode.ALL -> skipNext()
            RepeatMode.OFF -> {
                if (currentIndex < _queue.value.lastIndex) {
                    skipNext()
                } else {
                    pause()
                }
            }
        }
    }

    private fun nextShuffledIndex(): Int {
        if (shuffledIndices.isEmpty()) return 0

        val currentShuffledPos = shuffledIndices.indexOf(currentIndex)
        val nextPos = if (currentShuffledPos < 0) 0 else (currentShuffledPos + 1) % shuffledIndices.size
        return shuffledIndices[nextPos]
    }

    private fun startProgressUpdates() {
        stopProgressUpdates()
        progressJob = scope.launch {
            while (isActive) {
                updatePlaybackPosition()
                delay(PlayerConstants.PROGRESS_UPDATE_INTERVAL_MS)
            }
        }
    }

    private fun stopProgressUpdates() {
        progressJob?.cancel()
        progressJob = null
    }

    private fun updatePlaybackPosition() {
        val player = mediaPlayer ?: return

        when (val state = _playbackState.value) {
            is PlayerState.Playing -> {
                val pos = player.currentPosition.toLong().coerceAtLeast(0L)
                _playbackState.value = state.copy(position = pos)
                refreshNotificationForCurrentState()
            }

            is PlayerState.Paused -> {
                val pos = player.currentPosition.toLong().coerceAtLeast(0L)
                _playbackState.value = state.copy(position = pos)
                refreshNotificationForCurrentState()
            }

            else -> Unit
        }
    }

    private fun startPlaybackForeground(song: Song) {
        val state = _playbackState.value
        val duration = currentDuration(state).takeIf { it > 0L } ?: song.durationMs
        val position = currentPosition(state)

        // Load album art asynchronously
        scope.launch(Dispatchers.IO) {
            if (currentAlbumArt == null || song.albumArtUri != null) {
                currentAlbumArt = notificationHelper.loadAlbumArt(song)
            }

            // Switch back to main thread to call startForeground
            scope.launch(Dispatchers.Main) {
                val notification = notificationHelper.buildNotification(
                    song = song,
                    isPlaying = state is PlayerState.Playing,
                    repeatMode = _repeatMode.value,
                    shuffleEnabled = _shuffleEnabled.value,
                    positionMs = position,
                    durationMs = duration,
                    albumArt = currentAlbumArt
                )
                startForeground(NOTIFICATION_ID, notification)
            }
        }
    }

    private fun refreshNotificationForCurrentState() {
        if (!canPostNotifications()) return

        val state = _playbackState.value
        val song = currentSong(state) ?: return

        notificationHelper.updateNotification(
            notificationHelper.buildNotification(
                song = song,
                isPlaying = state is PlayerState.Playing,
                repeatMode = _repeatMode.value,
                shuffleEnabled = _shuffleEnabled.value,
                positionMs = currentPosition(state),
                durationMs = currentDuration(state).takeIf { it > 0L } ?: song.durationMs,
                albumArt = currentAlbumArt
            )
        )
    }

    private fun canPostNotifications(): Boolean {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU) return true
        return ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED
    }

    private fun stopPlayback() {
        stopProgressUpdates()
        releasePlayer()
        _playbackState.value = PlayerState.Idle
        stopForeground(STOP_FOREGROUND_REMOVE)
        stopSelf()
    }

    private fun releasePlayer() {
        mediaPlayer?.runCatching {
            setOnPreparedListener(null)
            setOnCompletionListener(null)
            setOnErrorListener(null)
            stop()
        }
        mediaPlayer?.release()
        mediaPlayer = null
        stopProgressUpdates()
        abandonAudioFocus()
    }

    private fun requestAudioFocus(): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val request = AudioFocusRequest.Builder(AudioManager.AUDIOFOCUS_GAIN)
                .setAudioAttributes(
                    AudioAttributes.Builder()
                        .setUsage(AudioAttributes.USAGE_MEDIA)
                        .setContentType(AudioAttributes.CONTENT_TYPE_MUSIC)
                        .build()
                )
                .setOnAudioFocusChangeListener(this)
                .build()
            audioFocusRequest = request
            audioManager.requestAudioFocus(request) == AudioManager.AUDIOFOCUS_REQUEST_GRANTED
        } else {
            @Suppress("DEPRECATION")
            audioManager.requestAudioFocus(
                this,
                AudioManager.STREAM_MUSIC,
                AudioManager.AUDIOFOCUS_GAIN
            ) == AudioManager.AUDIOFOCUS_REQUEST_GRANTED
        }
    }

    private fun abandonAudioFocus() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            audioFocusRequest?.let { audioManager.abandonAudioFocusRequest(it) }
            audioFocusRequest = null
        } else {
            @Suppress("DEPRECATION")
            audioManager.abandonAudioFocus(this)
        }
    }

    override fun onAudioFocusChange(focusChange: Int) {
        when (focusChange) {
            AudioManager.AUDIOFOCUS_LOSS,
            AudioManager.AUDIOFOCUS_LOSS_TRANSIENT -> pause()

            AudioManager.AUDIOFOCUS_LOSS_TRANSIENT_CAN_DUCK -> Unit
            AudioManager.AUDIOFOCUS_GAIN -> {
                if (_playbackState.value is PlayerState.Paused) {
                    resume()
                }
            }
        }
    }

    override fun onDestroy() {
        super.onDestroy()
        stopProgressUpdates()
        releasePlayer()
        stopForeground(STOP_FOREGROUND_REMOVE)
        scope.cancel()
    }
}

package com.example.music

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import android.graphics.Bitmap
import android.graphics.Canvas
import android.graphics.Color
import android.graphics.drawable.Drawable
import android.os.Build
import androidx.core.app.NotificationCompat
import androidx.media.app.NotificationCompat.MediaStyle
import coil.Coil
import coil.request.ImageRequest
import coil.target.Target
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext

class PlaybackNotificationHelper(
    private val context: Context
) {
    private val notificationManager = context.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
    private var currentAlbumArt: Bitmap? = null

    companion object {
        const val CHANNEL_ID = "music_playback_channel"
        const val NOTIFICATION_ID = 1001

        const val ACTION_PLAY = "com.example.music.PLAY"
        const val ACTION_PAUSE = "com.example.music.PAUSE"
        const val ACTION_NEXT = "com.example.music.NEXT"
        const val ACTION_PREVIOUS = "com.example.music.PREVIOUS"
        const val ACTION_STOP = "com.example.music.STOP"
        const val ACTION_REPEAT = "com.example.music.REPEAT"
        const val ACTION_SHUFFLE = "com.example.music.SHUFFLE"
    }

    init {
        createChannel()
    }

    private fun createChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                "Music Playback",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Controls music playback"
                setShowBadge(false)
                lockscreenVisibility = Notification.VISIBILITY_PUBLIC
                setSound(null, null)
                enableVibration(false)
            }
            notificationManager.createNotificationChannel(channel)
        }
    }

    suspend fun loadAlbumArt(song: Song): Bitmap? = withContext(Dispatchers.IO) {
        if (song.albumArtUri == null) return@withContext null

        return@withContext try {
            val drawable = Coil.imageLoader(context).execute(
                ImageRequest.Builder(context)
                    .data(song.albumArtUri)
                    .allowHardware(false)
                    .size(512, 512)
                    .build()
            ).drawable

            drawable?.let { convertDrawableToBitmap(it) }
        } catch (e: Exception) {
            null
        }
    }

    private fun convertDrawableToBitmap(drawable: Drawable): Bitmap {
        if (drawable.intrinsicWidth <= 0 || drawable.intrinsicHeight <= 0) {
            return Bitmap.createBitmap(512, 512, Bitmap.Config.ARGB_8888).apply {
                Canvas(this).apply {
                    drawColor(Color.GRAY)
                }
            }
        }

        val bitmap = Bitmap.createBitmap(
            drawable.intrinsicWidth,
            drawable.intrinsicHeight,
            Bitmap.Config.ARGB_8888
        )
        val canvas = Canvas(bitmap)
        drawable.setBounds(0, 0, canvas.width, canvas.height)
        drawable.draw(canvas)
        return bitmap
    }

    fun buildNotification(
        song: Song,
        isPlaying: Boolean,
        repeatMode: RepeatMode,
        shuffleEnabled: Boolean,
        positionMs: Long,
        durationMs: Long,
        albumArt: Bitmap? = null
    ): Notification {
        currentAlbumArt = albumArt

        val playIntent = if (isPlaying) ACTION_PAUSE else ACTION_PLAY
        val playIcon = if (isPlaying) android.R.drawable.ic_media_pause else android.R.drawable.ic_media_play
        val playText = if (isPlaying) "Pause" else "Play"

        val repeatIcon = when (repeatMode) {
            RepeatMode.OFF -> android.R.drawable.ic_menu_revert
            RepeatMode.ALL -> android.R.drawable.ic_menu_rotate
            RepeatMode.ONE -> android.R.drawable.ic_menu_more
        }

        val shuffleIcon = if (shuffleEnabled) {
            android.R.drawable.ic_menu_sort_by_size
        } else {
            android.R.drawable.ic_menu_sort_alphabetically
        }

        return NotificationCompat.Builder(context, CHANNEL_ID)
            .setContentTitle(song.title)
            .setContentText(song.artist)
            .setSubText(song.album)
            .setContentIntent(createOpenAppIntent())
            .setDeleteIntent(createPendingIntent(ACTION_STOP))
            .setSmallIcon(android.R.drawable.ic_media_play)
            .setLargeIcon(albumArt)
            .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .setOngoing(isPlaying)
            .setShowWhen(false)
            .setCategory(NotificationCompat.CATEGORY_TRANSPORT)
            .setStyle(
                MediaStyle()
                    .setMediaSession(null)
                    .setShowActionsInCompactView(0, 1, 2)
                    .setShowCancelButton(false)
            )
            .addAction(
                NotificationCompat.Action(
                    android.R.drawable.ic_media_previous,
                    "Previous",
                    createPendingIntent(ACTION_PREVIOUS, 1)
                )
            )
            .addAction(
                NotificationCompat.Action(
                    playIcon,
                    playText,
                    createPendingIntent(playIntent, 2)
                )
            )
            .addAction(
                NotificationCompat.Action(
                    android.R.drawable.ic_media_next,
                    "Next",
                    createPendingIntent(ACTION_NEXT, 3)
                )
            )
            .addAction(
                NotificationCompat.Action(
                    repeatIcon,
                    "Repeat",
                    createPendingIntent(ACTION_REPEAT, 4)
                )
            )
            .addAction(
                NotificationCompat.Action(
                    shuffleIcon,
                    "Shuffle",
                    createPendingIntent(ACTION_SHUFFLE, 5)
                )
            )
            .setProgress(
                durationMs.toInt(),
                positionMs.toInt(),
                durationMs <= 0L
            )
            .build()
    }

    private fun createOpenAppIntent(): PendingIntent {
        val intent = Intent(context, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_SINGLE_TOP or Intent.FLAG_ACTIVITY_REORDER_TO_FRONT
        }
        return PendingIntent.getActivity(
            context,
            0,
            intent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )
    }

    private fun createPendingIntent(action: String, requestCode: Int = 0): PendingIntent {
        val intent = Intent(context, MusicService::class.java).apply {
            this.action = action
        }
        return PendingIntent.getService(
            context,
            requestCode,
            intent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )
    }

    fun updateNotification(notification: Notification) {
        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    fun cancelNotification() {
        notificationManager.cancel(NOTIFICATION_ID)
    }

    fun updateAlbumArt(bitmap: Bitmap) {
        currentAlbumArt = bitmap
    }
}

package com.example.music

import android.app.Notification
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import android.graphics.Bitmap
import android.graphics.Canvas
import android.graphics.Color
import android.graphics.drawable.Drawable
import android.os.Build
import androidx.core.app.NotificationCompat
import androidx.media.app.NotificationCompat.DecoratedMediaCustomViewStyle
import androidx.media.app.NotificationCompat.MediaStyle
import coil.Coil
import coil.request.ImageRequest
import coil.target.Target
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext

class PlaybackNotificationHelper(
    private val context: Context
) {
    private val notificationManager = context.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
    private var currentAlbumArt: Bitmap? = null

    companion object {
        const val CHANNEL_ID = "music_playback_channel"
        const val NOTIFICATION_ID = 1001

        const val ACTION_PLAY = "com.example.music.PLAY"
        const val ACTION_PAUSE = "com.example.music.PAUSE"
        const val ACTION_NEXT = "com.example.music.NEXT"
        const val ACTION_PREVIOUS = "com.example.music.PREVIOUS"
        const val ACTION_STOP = "com.example.music.STOP"
        const val ACTION_REPEAT = "com.example.music.REPEAT"
        const val ACTION_SHUFFLE = "com.example.music.SHUFFLE"
    }

    init {
        createChannel()
    }

    private fun createChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                "Music Playback",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Controls music playback"
                setShowBadge(false)
                lockscreenVisibility = Notification.VISIBILITY_PUBLIC
                setSound(null, null)
                enableVibration(false)
            }
            notificationManager.createNotificationChannel(channel)
        }
    }

    suspend fun loadAlbumArt(song: Song): Bitmap? = withContext(Dispatchers.IO) {
        if (song.albumArtUri == null) return@withContext null

        return@withContext try {
            val drawable = Coil.imageLoader(context).execute(
                ImageRequest.Builder(context)
                    .data(song.albumArtUri)
                    .allowHardware(false)
                    .size(512, 512)
                    .build()
            ).drawable

            drawable?.let { convertDrawableToBitmap(it) }
        } catch (e: Exception) {
            null
        }
    }

    private fun convertDrawableToBitmap(drawable: Drawable): Bitmap {
        if (drawable.intrinsicWidth <= 0 || drawable.intrinsicHeight <= 0) {
            return Bitmap.createBitmap(512, 512, Bitmap.Config.ARGB_8888).apply {
                Canvas(this).apply {
                    drawColor(Color.GRAY)
                }
            }
        }

        val bitmap = Bitmap.createBitmap(
            drawable.intrinsicWidth,
            drawable.intrinsicHeight,
            Bitmap.Config.ARGB_8888
        )
        val canvas = Canvas(bitmap)
        drawable.setBounds(0, 0, canvas.width, canvas.height)
        drawable.draw(canvas)
        return bitmap
    }

    fun buildNotification(
        song: Song,
        isPlaying: Boolean,
        repeatMode: RepeatMode,
        shuffleEnabled: Boolean,
        positionMs: Long,
        durationMs: Long,
        albumArt: Bitmap? = null
    ): Notification {
        currentAlbumArt = albumArt

        val playIntent = if (isPlaying) ACTION_PAUSE else ACTION_PLAY
        val playIcon = if (isPlaying) android.R.drawable.ic_media_pause else android.R.drawable.ic_media_play
        val playText = if (isPlaying) "Pause" else "Play"

        val repeatIcon = when (repeatMode) {
            RepeatMode.OFF -> android.R.drawable.ic_menu_revert
            RepeatMode.ALL -> android.R.drawable.ic_menu_rotate
            RepeatMode.ONE -> android.R.drawable.ic_menu_more
        }

        val shuffleIcon = if (shuffleEnabled) {
            android.R.drawable.ic_menu_sort_by_size
        } else {
            android.R.drawable.ic_menu_sort_alphabetically
        }

        // Build notification with all modern media features
        val builder = NotificationCompat.Builder(context, CHANNEL_ID)
            .setContentTitle(song.title)
            .setContentText(song.artist)
            .setSubText(song.album)
            .setSmallIcon(android.R.drawable.ic_media_play)
            .setLargeIcon(albumArt)  // Album artwork
            .setContentIntent(createOpenAppIntent())
            .setDeleteIntent(createPendingIntent(ACTION_STOP))
            .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
            .setCategory(NotificationCompat.CATEGORY_TRANSPORT)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .setShowWhen(false)
            .setNotificationSilent()
            // Ensure notification stays when playing
            .setOngoing(isPlaying)
            // Add progress bar for seek
            .setProgress(
                durationMs.toInt(),
                positionMs.toInt(),
                durationMs <= 0L
            )
            // Add playback controls
            .addAction(
                NotificationCompat.Action(
                    android.R.drawable.ic_media_previous,
                    "Previous",
                    createPendingIntent(ACTION_PREVIOUS, 1)
                )
            )
            .addAction(
                NotificationCompat.Action(
                    playIcon,
                    playText,
                    createPendingIntent(playIntent, 2)
                )
            )
            .addAction(
                NotificationCompat.Action(
                    android.R.drawable.ic_media_next,
                    "Next",
                    createPendingIntent(ACTION_NEXT, 3)
                )
            )
            .addAction(
                NotificationCompat.Action(
                    repeatIcon,
                    "Repeat",
                    createPendingIntent(ACTION_REPEAT, 4)
                )
            )
            .addAction(
                NotificationCompat.Action(
                    shuffleIcon,
                    "Shuffle",
                    createPendingIntent(ACTION_SHUFFLE, 5)
                )
            )

        // Apply modern MediaStyle with all controls visible
        val mediaStyle = MediaStyle()
            .setShowActionsInCompactView(0, 1, 2, 3, 4)  // Show all actions: Previous, Play/Pause, Next, Repeat, Shuffle
            .setShowCancelButton(true)
            .setCancelButtonIntent(createPendingIntent(ACTION_STOP))

        builder.setStyle(mediaStyle)

        return builder.build()
    }

    private fun createOpenAppIntent(): PendingIntent {
        val intent = Intent(context, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_SINGLE_TOP or Intent.FLAG_ACTIVITY_REORDER_TO_FRONT
        }
        return PendingIntent.getActivity(
            context,
            0,
            intent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )
    }

    private fun createPendingIntent(action: String, requestCode: Int = 0): PendingIntent {
        val intent = Intent(context, MusicService::class.java).apply {
            this.action = action
        }
        return PendingIntent.getService(
            context,
            requestCode,
            intent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )
    }

    fun updateNotification(notification: Notification) {
        notificationManager.notify(NOTIFICATION_ID, notification)
    }

    fun cancelNotification() {
        notificationManager.cancel(NOTIFICATION_ID)
    }

    fun updateAlbumArt(bitmap: Bitmap) {
        currentAlbumArt = bitmap
    }
}

package com.example.music

import androidx.compose.runtime.Stable

@Stable
sealed class PlayerState {
    object Idle : PlayerState()
    object Preparing : PlayerState()
    data class Ready(val song: Song, val duration: Long) : PlayerState()
    data class Playing(val song: Song, val position: Long, val duration: Long) : PlayerState()
    data class Paused(val song: Song, val position: Long, val duration: Long) : PlayerState()
    data class Error(val message: String, val song: Song? = null) : PlayerState()
}

@Stable
sealed class Result<out T> {
    object Loading : Result<Nothing>()
    data class Success<T>(val data: T) : Result<T>()
    data class Error(val message: String) : Result<Nothing>()
}

@Stable
data class PlaybackState(
    val playerState: PlayerState = PlayerState.Idle,
    val queue: List<Song> = emptyList(),
    val currentIndex: Int = -1,
    val repeatMode: RepeatMode = RepeatMode.ALL,
    val shuffleEnabled: Boolean = false,
    val shuffledIndices: List<Int> = emptyList()
)

@Stable
data class LibraryState(
    val songs: List<Song> = emptyList(),
    val favorites: Set<Long> = emptySet(),
    val playlists: List<Playlist> = emptyList(),
    val recents: List<Long> = emptyList(),
    val playCounts: Map<Long, Int> = emptyMap(),
    val recentSearches: List<String> = emptyList(),
    val isLoading: Boolean = false,
    val error: String? = null
)

@Stable
data class UiSong(
    val song: Song,
    val isFavorite: Boolean,
    val playCount: Int = 0
)

@Stable
data class MusicUiState(
    val library: LibraryState = LibraryState(),
    val playback: PlaybackState = PlaybackState(),
    val selectedScreen: AppScreen = AppScreen.HOME,
    val selectedSongIds: Set<Long> = emptySet(),
    val searchQuery: String = "",
    val searchFilter: SearchFilter = SearchFilter.SONG,
    val sleepTimer: SleepTimerState = SleepTimerState(),
    val equalizer: EqualizerState = EqualizerState()
)

@Stable
data class SleepTimerState(
    val targetTimeMs: Long? = null,
    val remainingMs: Long = 0L,
    val isActive: Boolean = false
)

@Stable
data class EqualizerState(
    val levels: List<Int> = emptyList(),
    val range: Pair<Int, Int> = -1500 to 1500,
    val isEnabled: Boolean = false,
    val error: String? = null
)

enum class AppScreen { HOME, PLAYLISTS, SEARCH, SETTINGS }
enum class RepeatMode { OFF, ALL, ONE }
enum class SearchFilter { SONG, ARTIST, ALBUM }

package com.example.music

import androidx.compose.runtime.Stable

@Stable
sealed class PlayerState {
    object Idle : PlayerState()
    object Preparing : PlayerState()
    data class Ready(val song: Song, val duration: Long) : PlayerState()
    data class Playing(val song: Song, val position: Long, val duration: Long) : PlayerState()
    data class Paused(val song: Song, val position: Long, val duration: Long) : PlayerState()
    data class Error(val message: String, val song: Song? = null) : PlayerState()
}

@Stable
sealed class Result<out T> {
    object Loading : Result<Nothing>()
    data class Success<T>(val data: T) : Result<T>()
    data class Error(val message: String) : Result<Nothing>()
}

@Stable
data class PlaybackState(
    val playerState: PlayerState = PlayerState.Idle,
    val queue: List<Song> = emptyList(),
    val currentIndex: Int = -1,
    val repeatMode: RepeatMode = RepeatMode.ALL,
    val shuffleEnabled: Boolean = false,
    val shuffledIndices: List<Int> = emptyList()
)

@Stable
data class LibraryState(
    val songs: List<Song> = emptyList(),
    val favorites: Set<Long> = emptySet(),
    val playlists: List<Playlist> = emptyList(),
    val recents: List<Long> = emptyList(),
    val playCounts: Map<Long, Int> = emptyMap(),
    val recentSearches: List<String> = emptyList(),
    val isLoading: Boolean = false,
    val error: String? = null
)

@Stable
data class UiSong(
    val song: Song,
    val isFavorite: Boolean,
    val playCount: Int = 0
)

@Stable
data class MusicUiState(
    val library: LibraryState = LibraryState(),
    val playback: PlaybackState = PlaybackState(),
    val selectedScreen: AppScreen = AppScreen.HOME,
    val selectedSongIds: Set<Long> = emptySet(),
    val searchQuery: String = "",
    val searchFilter: SearchFilter = SearchFilter.SONG,
    val sleepTimer: SleepTimerState = SleepTimerState(),
    val equalizer: EqualizerState = EqualizerState()
)

@Stable
data class SleepTimerState(
    val targetTimeMs: Long? = null,
    val remainingMs: Long = 0L,
    val isActive: Boolean = false
)

@Stable
data class EqualizerState(
    val levels: List<Int> = emptyList(),
    val range: Pair<Int, Int> = -1500 to 1500,
    val isEnabled: Boolean = false,
    val error: String? = null
)

enum class AppScreen { HOME, PLAYLISTS, SEARCH, SETTINGS }
enum class RepeatMode { OFF, ALL, ONE }
enum class SearchFilter { SONG, ARTIST, ALBUM }
enum class LibrarySortOption { TITLE_ASC, TITLE_DESC, ARTIST, RECENTLY_ADDED, DURATION }

package com.example.music.ui.screens

import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.horizontalScroll
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Clear
import androidx.compose.material.icons.filled.Favorite
import androidx.compose.material.icons.filled.FavoriteBorder
import androidx.compose.material.icons.filled.Search
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import com.example.music.LibraryState
import com.example.music.SearchFilter
import com.example.music.Song
import com.example.music.UiSong
import com.example.music.ui.components.AlbumArt

@Composable
fun SearchScreen(
    libraryState: LibraryState,
    searchQuery: String,
    searchFilter: SearchFilter,
    selectedSongIds: Set<Long>,
    filteredSongs: List<UiSong>,
    onSearchQueryChange: (String) -> Unit,
    onSearchFilterChange: (SearchFilter) -> Unit,
    onPlaySong: (Song, List<Song>) -> Unit,
    onToggleFavorite: (Long) -> Unit,
    onToggleSongSelection: (Long) -> Unit,
) {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(MaterialTheme.colorScheme.background)
    ) {
        // Search bar with filters
        SearchHeader(
            searchQuery = searchQuery,
            searchFilter = searchFilter,
            onSearchQueryChange = onSearchQueryChange,
            onSearchFilterChange = onSearchFilterChange
        )

        // Search results or recent searches
        if (searchQuery.isEmpty()) {
            RecentSearchesSection(
                recentSearches = libraryState.recentSearches,
                onSearchQueryChange = onSearchQueryChange
            )
        } else {
            SearchResultsSection(
                filteredSongs = filteredSongs,
                selectedSongIds = selectedSongIds,
                searchQuery = searchQuery,
                onPlaySong = onPlaySong,
                onToggleFavorite = onToggleFavorite,
                onToggleSongSelection = onToggleSongSelection
            )
        }
    }
}

@Composable
private fun SearchHeader(
    searchQuery: String,
    searchFilter: SearchFilter,
    onSearchQueryChange: (String) -> Unit,
    onSearchFilterChange: (SearchFilter) -> Unit
) {
    Column(
        verticalArrangement = Arrangement.spacedBy(12.dp),
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 16.dp)
            .background(MaterialTheme.colorScheme.background)
    ) {
        // Search field
        TextField(
            value = searchQuery,
            onValueChange = onSearchQueryChange,
            modifier = Modifier
                .fillMaxWidth()
                .clip(RoundedCornerShape(24.dp)),
            placeholder = {
                Text(
                    "Search songs, artists, albums",
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            },
            leadingIcon = {
                Icon(
                    imageVector = Icons.Default.Search,
                    contentDescription = null,
                    tint = MaterialTheme.colorScheme.onSurface,
                    modifier = Modifier.size(20.dp)
                )
            },
            trailingIcon = {
                if (searchQuery.isNotEmpty()) {
                    IconButton(onClick = { onSearchQueryChange("") }) {
                        Icon(
                            imageVector = Icons.Default.Clear,
                            contentDescription = "Clear",
                            tint = MaterialTheme.colorScheme.onSurfaceVariant,
                            modifier = Modifier.size(18.dp)
                        )
                    }
                }
            },
            singleLine = true,
            colors = TextFieldDefaults.colors(
                focusedContainerColor = MaterialTheme.colorScheme.surfaceVariant,
                unfocusedContainerColor = MaterialTheme.colorScheme.surfaceVariant,
                disabledContainerColor = MaterialTheme.colorScheme.surfaceVariant,
                focusedIndicatorColor = Color.Transparent,
                unfocusedIndicatorColor = Color.Transparent,
                focusedTextColor = MaterialTheme.colorScheme.onSurface,
                unfocusedTextColor = MaterialTheme.colorScheme.onSurface,
                cursorColor = MaterialTheme.colorScheme.primary
            )
        )

        // Filter chips
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .horizontalScroll(rememberScrollState()),
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            SearchFilter.values().forEach { filter ->
                FilterChip(
                    selected = searchFilter == filter,
                    onClick = { onSearchFilterChange(filter) },
                    label = {
                        Text(
                            text = when (filter) {
                                SearchFilter.SONG -> "Songs"
                                SearchFilter.ARTIST -> "Artists"
                                SearchFilter.ALBUM -> "Albums"
                            }
                        )
                    }
                )
            }
        }
    }
}

@Composable
private fun RecentSearchesSection(
    recentSearches: List<String>,
    onSearchQueryChange: (String) -> Unit
) {
    if (recentSearches.isEmpty()) {
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.Center
        ) {
            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                Icon(
                    imageVector = Icons.Default.Search,
                    contentDescription = null,
                    tint = MaterialTheme.colorScheme.onSurfaceVariant,
                    modifier = Modifier.size(48.dp)
                )
                Spacer(modifier = Modifier.height(12.dp))
                Text(
                    text = "Start searching",
                    style = MaterialTheme.typography.titleMedium,
                    color = MaterialTheme.colorScheme.onSurface
                )
                Spacer(modifier = Modifier.height(4.dp))
                Text(
                    text = "Your search history will appear here",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
        }
        return
    }

    LazyColumn(
        contentPadding = PaddingValues(horizontal = 16.dp, vertical = 16.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp),
        modifier = Modifier.fillMaxSize()
    ) {
        item {
            Text(
                text = "Recent Searches",
                style = MaterialTheme.typography.titleSmall,
                fontWeight = FontWeight.SemiBold,
                color = MaterialTheme.colorScheme.onSurface
            )
            Spacer(modifier = Modifier.height(8.dp))
        }
        items(recentSearches) { query ->
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .clip(RoundedCornerShape(8.dp))
                    .clickable { onSearchQueryChange(query) }
                    .background(MaterialTheme.colorScheme.surfaceVariant)
                    .padding(12.dp),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.spacedBy(12.dp)
            ) {
                Icon(
                    imageVector = Icons.Default.Search,
                    contentDescription = null,
                    tint = MaterialTheme.colorScheme.onSurfaceVariant,
                    modifier = Modifier.size(20.dp)
                )
                Text(
                    text = query,
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onSurface
                )
            }
        }
    }
}

@Composable
private fun SearchResultsSection(
    filteredSongs: List<UiSong>,
    selectedSongIds: Set<Long>,
    searchQuery: String,
    onPlaySong: (Song, List<Song>) -> Unit,
    onToggleFavorite: (Long) -> Unit,
    onToggleSongSelection: (Long) -> Unit
) {
    if (filteredSongs.isEmpty()) {
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.Center
        ) {
            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                Text(
                    text = "No results for \"$searchQuery\"",
                    style = MaterialTheme.typography.titleMedium,
                    color = MaterialTheme.colorScheme.onSurface
                )
                Spacer(modifier = Modifier.height(8.dp))
                Text(
                    text = "Try different keywords",
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
        }
        return
    }

    LazyColumn(
        contentPadding = PaddingValues(horizontal = 12.dp, vertical = 12.dp),
        verticalArrangement = Arrangement.spacedBy(4.dp),
        modifier = Modifier.fillMaxSize()
    ) {
        item {
            Text(
                text = "${filteredSongs.size} results",
                style = MaterialTheme.typography.labelMedium,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
                modifier = Modifier.padding(horizontal = 4.dp, vertical = 8.dp)
            )
        }
        items(filteredSongs, key = { it.song.id }) { uiSong ->
            SearchSongItem(
                song = uiSong.song,
                isFavorite = uiSong.isFavorite,
                isSelected = selectedSongIds.contains(uiSong.song.id),
                playCount = uiSong.playCount,
                onPlay = { onPlaySong(uiSong.song, filteredSongs.map { it.song }) },
                onToggleFavorite = { onToggleFavorite(uiSong.song.id) },
                onToggleSelection = { onToggleSongSelection(uiSong.song.id) }
            )
        }
        item { Spacer(modifier = Modifier.height(80.dp)) }
    }
}

@Composable
private fun SearchSongItem(
    song: Song,
    isFavorite: Boolean,
    isSelected: Boolean,
    playCount: Int,
    onPlay: () -> Unit,
    onToggleFavorite: () -> Unit,
    onToggleSelection: () -> Unit
) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .padding(vertical = 4.dp)
            .clip(RoundedCornerShape(8.dp))
            .background(
                if (isSelected) MaterialTheme.colorScheme.surfaceVariant
                else Color.Transparent
            )
            .clickable { onPlay() }
            .padding(8.dp),
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        // Album Art
        AlbumArt(
            uri = song.albumArtUri,
            modifier = Modifier
                .size(40.dp)
                .clip(RoundedCornerShape(4.dp))
        )

        // Song Info
        Column(
            modifier = Modifier
                .weight(1f)
                .fillMaxHeight(),
            verticalArrangement = Arrangement.Center
        ) {
            Text(
                text = song.title,
                style = MaterialTheme.typography.bodySmall,
                fontWeight = FontWeight.SemiBold,
                color = MaterialTheme.colorScheme.onSurface,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
            Text(
                text = "${song.artist} • ${song.album}",
                style = MaterialTheme.typography.labelSmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
                maxLines = 1,
                overflow = TextOverflow.Ellipsis
            )
            if (playCount > 0) {
                Text(
                    text = "Played $playCount times",
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f)
                )
            }
        }

        // Favorite Button
        IconButton(
            onClick = onToggleFavorite,
            modifier = Modifier.size(24.dp)
        ) {
            Icon(
                imageVector = if (isFavorite) Icons.Filled.Favorite else Icons.Filled.FavoriteBorder,
                contentDescription = if (isFavorite) "Remove from favorites" else "Add to favorites",
                tint = if (isFavorite) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.onSurfaceVariant,
                modifier = Modifier.size(18.dp)
            )
        }
    }
}
